#!/usr/bin/env bash
# wedding-event.sh — 婚礼/活动一天流程 (Wedding / Event) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="婚礼/活动一天流程 (Wedding / Event)"

usage() {
  cat <<EOF
wedding-event.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./wedding-event.sh             # interactive
  ./wedding-event.sh --dry-run
  ./wedding-event.sh --json
  ./wedding-event.sh --explain
  ./wedding-event.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "婚礼/活动一天流程 (Wedding / Event)" 工作流。

一句话: 从接单到交付一整场不可重来的活动——靠 timeline、关键时刻清单、冗余备份把「一次性、高压、不可 retake」变成可控流程。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**行前 timeline + 勘景**: 与客户敲定当天时间线（化妆/仪式/合影/宴会），提前看场地光线与机位，做关键时刻 + 家庭合影清单。跳过 → 当天乱套、错过仪式、漏拍关键家人。(evidence: [T03-S011])"
  "**关键时刻清单**: 列「必拍」（戒指、宣誓、初吻、第一支舞、合影名单）。跳过 → 漏掉不可重来的核心瞬间 = 灾难性投诉。(evidence: [T03-S011])"
  "**双机 + 备份策略**: 带 ≥2 机身、多镜、多卡多电；机身开**双卡同时写入**，关键节点后**立即下卡备份**到多块盘 + 云/异地。跳过双卡冗余 → 一张卡损坏 = 整场丢失、无法挽回的法律/声誉风险。(evidence: [T03-S012])"
  "**当天节奏执行**: 按 timeline 走但留 15–20 分钟缓冲吸收延误，盯光/盯清单/不慌。跳过缓冲 → 一处延误连锁崩盘，赶场漏拍。(evidence: [T03-S011])"
  "**交付**: 选片（量大，AI 选片救场）→ 调色统一风格 → 客片平台在线交付。跳过统一调色 → 一套照片色调跳跃显业余。(evidence: [T02-S027])"
)
declare -a FAILURE_MODES=(
  "**单卡无冗余**: 卡损坏整场丢失 → 永远开机内双卡 + 当天立即下卡到多盘（3-2-1 备份）。**CLI 自检**: 「机身开双卡了吗？当天下午备份到了至少两个物理位置吗？」"
  "**timeline 无缓冲**: 一处延误连锁崩盘 → 每段间塞 15–20 分钟缓冲。**CLI 自检**: 「你的当天时间线给延误留了缓冲，还是排得满满？」"
  "**没勘景/没合影名单**: 漏拍关键家人 → 行前确认合影名单 + 指定一名亲友当天叫人。**CLI 自检**: 「合影名单和叫人的人，行前定好了吗？」"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "wedding-event-walkthrough"
fi
